import sys
from typing import List

class Solution:
    def solve(self, V: int, E: int, edges: List[List[int]]) -> List[List[int]]:
        adj_list = [[] for _ in range(V + 1)]
        for u, v in edges:
            adj_list[u].append(v)
            adj_list[v].append(u)
        return [sorted(adj) for adj in adj_list[1:]]

if __name__ == '__main__':
