#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<vector<int>> solve(int V, int E, vector<vector<int>>& edges) {
        vector<vector<int>> adj_list(V + 1);
        for (auto& edge : edges) {
            int u = edge[0], v = edge[1];
            adj_list[u].push_back(v);
            adj_list[v].push_back(u);
        }
        vector<vector<int>> result;
        for (int i = 1; i <= V; i++) {
            sort(adj_list[i].begin(), adj_list[i].end());
            result.push_back(adj_list[i]);
        }
        return result;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int V, E;
    if (!(cin >> V >> E)) return 0;
    vector<vector<int>> edges(E, vector<int>(2));
    for (auto& edge : edges) cin >> edge[0] >> edge[1];
    Solution sol;
    vector<vector<int>> ans = sol.solve(V, E, edges);
    for (auto& adj : ans) {
        for (int v : adj) cout << v << " ";
        cout << "\n";
    }
    return 0;
}
